mapper.select:
SELECT v.version_no, v.app_cd, v.store_cd, v.version, v.app_code, v.release_dt, v.force_update_yn, v.use_yn, v.note, v.created_at, v.created_by, v.updated_at, v.updated_by, at_cd.code_nm AS app_type_nm, st_cd.code_nm AS store_type_nm FROM app_version v LEFT JOIN com_code at_cd ON at_cd.grp_cd = 'APP_TYPE_CD' AND at_cd.code = v.app_cd LEFT JOIN com_code st_cd ON st_cd.grp_cd = 'STORE_TYPE_CD' AND st_cd.code = v.store_cd
AND v.app_cd = #{searchAppCd}
AND v.store_cd = #{searchStoreCd}
ORDER BY v.app_cd, v.store_cd, v.release_dt DESC, v.version_no DESC
